// Получаем текст из ноды Edit Fields
const text = $('Code').first().json.result;

// Логируем входной текст для отладки
console.log('Input text:', text);

// Проверяем, что текст — строка
if (!text || typeof text !== 'string') {
  console.log('Error: Input text is not a valid string');
  return [];
}

// Нормализуем новые строки (на случай \r\n)
const normalizedText = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

// Разделяем текст только по новым строкам
let ideas = normalizedText.split('\n').map(idea => idea.trim()).filter(idea => idea.length > 0);

// Логируем идеи после разделения для отладки
console.log('Ideas after split:', ideas);

// Удаляем нумерацию (например, "1.", "1)", "1-") из начала каждой идеи
ideas = ideas.map(idea => idea.replace(/^\d+[.\)\-]\s*/, ''));

// Удаляем пустые идеи после очистки
ideas = ideas.filter(idea => idea.length > 0);

// Логируем финальные идеи для отладки
console.log('Final ideas:', ideas);

// Возвращаем массив объектов
return ideas.map(idea => ({ json: { idea } }));

// Получаем текст из нового формата данных
const fullText = $input.first().json.result;$input.first().json.result

// Логируем для отладки
console.log('Input text length:', fullText.length);
console.log('First 100 chars:', fullText.substring(0, 100));

// Разделяем по разделителю " --- " (с пробелами)
const tasks = fullText.split(' --- ');

// Создаем отдельные элементы для каждого ТЗ
const result = tasks.map((task, index) => {
  return {
    task_number: index + 1,
    task_content: task.trim(),
    total_tasks: tasks.length,
    content_length: task.trim().length,
  };
});

console.log('Total tasks found:', result.length);

return result;
